import{_ as t,o as i,c as a,a2 as s}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"GitHub Issue Trigger","description":"","frontmatter":{},"headers":[],"relativePath":"manual/github-issue-trigger.md","filePath":"manual/github-issue-trigger.md","lastUpdated":null}'),n={name:"manual/github-issue-trigger.md"};function o(l,e,r,h,d,p){return i(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="github-issue-trigger" tabindex="-1">GitHub Issue Trigger <a class="header-anchor" href="#github-issue-trigger" aria-label="Permalink to &quot;GitHub Issue Trigger&quot;">​</a></h1><p>Autofac can start a workflow run from a GitHub issue. This lets a team file a feature or bug, opt it into Autofac, and let a governed workflow plan, implement, review, and open a pull request.</p><h2 id="how-the-trigger-works" tabindex="-1">How the trigger works <a class="header-anchor" href="#how-the-trigger-works" aria-label="Permalink to &quot;How the trigger works&quot;">​</a></h2><ol><li>GitHub sends an <code>issues</code> webhook to <code>POST /webhooks/github</code>.</li><li>Autofac validates <code>X-Hub-Signature-256</code> against <code>Integrations:GitHub:WebhookSecret</code>.</li><li>Autofac checks the issue action against <code>Integrations:GitHub:TriggerActions</code>.</li><li>Autofac checks that the issue has the required label.</li><li>Autofac resolves the active workflow tagged <code>github-trigger</code>.</li><li>The run starts with issue title, body, labels, and URL in run context.</li><li>Agent and GitHub tool calls still pass through the Tool Gateway and policy.</li></ol><h2 id="required-label" tabindex="-1">Required label <a class="header-anchor" href="#required-label" aria-label="Permalink to &quot;Required label&quot;">​</a></h2><p>By default, the issue must carry the label <code>autofac</code>. This prevents every new issue from spending model budget or opening branches.</p><p>Configure the label:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Integrations__GitHub__RequiredLabel</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">autofac</span></span></code></pre></div><p>Matching is case-insensitive. Set the value to an empty string only if every matching issue action should start a run.</p><h2 id="configure-github-integration" tabindex="-1">Configure GitHub integration <a class="header-anchor" href="#configure-github-integration" aria-label="Permalink to &quot;Configure GitHub integration&quot;">​</a></h2><p>At minimum:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Integrations__GitHub__Enabled</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Integrations__GitHub__RepositoryOwner</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">owner</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Integrations__GitHub__RepositoryName</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">repo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Integrations__GitHub__PersonalAccessToken</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">secret</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Integrations__GitHub__WebhookSecret</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">shared-secret</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Integrations__GitHub__DefaultBaseBranch</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">main</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Integrations__GitHub__BranchPrefix</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">autofac/</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Integrations__GitHub__CreateDraftPullRequests</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span></span></code></pre></div><p>Use Settings to check GitHub readiness before enabling webhook traffic.</p><h2 id="configure-the-repository-webhook" tabindex="-1">Configure the repository webhook <a class="header-anchor" href="#configure-the-repository-webhook" aria-label="Permalink to &quot;Configure the repository webhook&quot;">​</a></h2><p>In GitHub repository settings:</p><ol><li>Add a webhook.</li><li>Set the payload URL to <code>https://&lt;your-autofac-host&gt;/webhooks/github</code>.</li><li>Set the content type to <code>application/json</code>.</li><li>Use the same shared secret as <code>Integrations:GitHub:WebhookSecret</code>.</li><li>Subscribe to the <code>issues</code> event.</li></ol><h2 id="configure-the-workflow" tabindex="-1">Configure the workflow <a class="header-anchor" href="#configure-the-workflow" aria-label="Permalink to &quot;Configure the workflow&quot;">​</a></h2><p>The workflow you want to start must be active and tagged:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>github-trigger</span></span></code></pre></div><p>The agent task can read trigger context through variables such as:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{{input.title}}</span></span>
<span class="line"><span>{{input.body}}</span></span>
<span class="line"><span>{{input.url}}</span></span></code></pre></div><h2 id="validate-the-flow" tabindex="-1">Validate the flow <a class="header-anchor" href="#validate-the-flow" aria-label="Permalink to &quot;Validate the flow&quot;">​</a></h2><ol><li>Create the <code>autofac</code> label in the repository.</li><li>Open a test issue with the label.</li><li>Confirm GitHub webhook delivery succeeds.</li><li>Confirm Autofac starts a run.</li><li>Inspect the run context and evidence pack.</li><li>Confirm any branch or pull request created by the workflow matches the configured prefix and draft setting.</li></ol><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Likely cause</th></tr></thead><tbody><tr><td>Webhook returns skipped</td><td>The action is not enabled, the label is missing, or no active <code>github-trigger</code> workflow exists.</td></tr><tr><td>Signature validation fails</td><td>The GitHub webhook secret and Autofac setting differ.</td></tr><tr><td>Run starts but GitHub actions fail</td><td>Repository owner/name/token or permissions are wrong.</td></tr><tr><td>Agent spends budget unexpectedly</td><td>Required label was disabled or issue templates apply it too broadly.</td></tr></tbody></table>`,25)])])}const c=t(n,[["render",o]]);export{g as __pageData,c as default};
